 1	import React, { FC } from 'react';
 2	import FirstItemListPopover from 'src/views/virtualmachines/list/components/FirstItemListPopover/FirstItemListPopover';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { NO_DATA_DASH } from '@kubevirt-utils/resources/vm/utils/constants';
 6	import { getPrintableNetworkInterfaceType } from '@kubevirt-utils/resources/vm/utils/network/selectors';
 7	import { TableData } from '@openshift-console/dynamic-plugin-sdk';
 8	import {
 9	  DescriptionList,
10	  DescriptionListDescription,
11	  DescriptionListGroup,
12	  DescriptionListTerm,
13	  DescriptionListTermHelpTextButton,
14	  Popover,
15	  PopoverPosition,
16	} from '@patternfly/react-core';
17	
18	import { InterfacesData } from './utils/types';
19	
20	type VirtualMachinesOverviewTabNetworkInterfacesProps = {
21	  activeColumnIDs: Set<string>;
22	  obj: InterfacesData;
23	};
24	
25	const VirtualMachinesOverviewTabInterfacesRow: FC<
26	  VirtualMachinesOverviewTabNetworkInterfacesProps
27	> = ({ activeColumnIDs, obj }) => {
28	  const { t } = useKubevirtTranslation();
29	  const popoverFields = {
30	    [t('Model')]: obj?.iface?.model,
31	    [t('Name')]: obj?.network?.name,
32	    [t('Network')]: obj?.network?.multus?.networkName || t('Pod networking'),
33	    [t('Type')]: getPrintableNetworkInterfaceType(obj?.iface),
34	  };
35	  return (
36	    <>
37	      <TableData activeColumnIDs={activeColumnIDs} id="name">
38	        <div data-test-id={`network-interface-${obj?.network?.name}`}>
39	          <DescriptionList>
40	            <Popover
41	              bodyContent={
42	                <DescriptionList isHorizontal>
43	                  {Object.entries(popoverFields).map(([key, value]) => (
44	                    <DescriptionListGroup key={key}>
45	                      <DescriptionListTerm>{key}</DescriptionListTerm>
46	                      <DescriptionListDescription>
47	                        {value || NO_DATA_DASH}
48	                      </DescriptionListDescription>
49	                    </DescriptionListGroup>
50	                  ))}
51	                </DescriptionList>
52	              }
53	              hasAutoWidth
54	              position={PopoverPosition.left}
55	            >
56	              <DescriptionListTermHelpTextButton>
57	                {obj?.iface?.name}
58	              </DescriptionListTermHelpTextButton>
59	            </Popover>
60	          </DescriptionList>
61	        </div>
62	      </TableData>
63	      <TableData activeColumnIDs={activeColumnIDs} id="ip">
64	        <div data-test-id={`network-interface-${obj?.ipAddresses}`}>
65	          <FirstItemListPopover
66	            headerContent={'IP addresses'}
67	            includeCopyFirstItem
68	            items={obj?.ipAddresses}
69	          />
70	        </div>
71	      </TableData>
72	    </>
73	  );
74	};
75	
76	export default VirtualMachinesOverviewTabInterfacesRow;

